rules.pseudocode:
for each action a:
  if a == 'eat' and food_at_position:
    Q_MB[s][a] = p_hat['food'|'eat',s] * r_D_food + (1 - p_hat['food'|'eat',s]) * r_D_nofood
  elif a in ['move_up','move_down','move_left','move_right']:
    s_next = compute_next_state(s, a)
    Q_MB[s][a] = c_step + gamma * max(Q_MF[s_next][a_prime] for a_prime in actions)
  else:
    Q_MB[s][a] = c_step

p_hat[o_obs|a,s] = p_hat[o_obs|a,s] + alpha_T * (1.0 - p_hat[o_obs|a,s])
for o != o_obs:
  p_hat[o|a,s] = p_hat[o|a,s] + alpha_T * (0.0 - p_hat[o|a,s])
